"use client";
import React, { useState } from 'react';

export default function PrivacySentinel() {
  const [text, setText] = useState("");
  const [socialUrl, setSocialUrl] = useState("");
  const [result, setResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const hardenedRisk = result?.risk_score || 0;

  const handleUrlScan = async () => {
    if (!socialUrl) return;
    setLoading(true);
    try {
      const res = await fetch('http://127.0.0.1:8000/analyze-url', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url: socialUrl }),
      });
      const data = await res.json();
      setText(data.extracted_text || "");
      setResult(data);
    } catch (err) { alert("Backend Error: Check port 8000"); }
    finally { setLoading(false); }
  };

  const handleUpload = async (e: any) => {
    if (!e.target.files?.[0]) return;
    const fd = new FormData();
    fd.append('file', e.target.files[0]);
    setLoading(true);
    try {
      const res = await fetch('http://127.0.0.1:8000/upload', { method: 'POST', body: fd });
      const data = await res.json();
      setText(data.extracted_text || "");
      setResult(data);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const handleAction = async () => {
    setLoading(true);
    try {
      const res = await fetch('http://127.0.0.1:8000/process', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: text }),
      });
      setResult(await res.json());
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  return (
    <div className="min-h-screen bg-black text-white p-8 font-mono">
      <div className="max-w-7xl mx-auto">
        <h1 className="text-3xl font-black text-blue-500 mb-8 border-l-4 border-blue-500 pl-4 uppercase tracking-tighter">
          SENTINEL: MULTI-PLATFORM OSINT AUDITOR
        </h1>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-6">
            
            {/* UNIFIED SOCIAL SCANNER */}
            <div className="bg-zinc-900 p-6 border border-zinc-800 rounded-2xl border-l-4 border-blue-500 shadow-2xl">
              <p className="text-[10px] text-blue-400 mb-3 uppercase font-black tracking-widest italic">Social Recon (LinkedIn / X / Facebook)</p>
              <div className="flex gap-3">
                <input 
                  type="text" 
                  className="bg-black border border-zinc-800 w-full p-3 rounded-xl text-xs outline-none focus:border-blue-500" 
                  placeholder="Paste Profile URL (e.g., facebook.com/user)" 
                  value={socialUrl} 
                  onChange={(e)=>setSocialUrl(e.target.value)} 
                />
                <button onClick={handleUrlScan} className="bg-blue-600 px-6 py-2 rounded-xl text-xs font-black hover:bg-blue-500 transition-all active:scale-95">SCAN</button>
              </div>
            </div>

            {/* DOCUMENT AUDIT */}
            <div className="bg-zinc-900 p-6 border border-zinc-800 rounded-2xl">
              <p className="text-[10px] text-zinc-500 mb-3 uppercase font-black">Offline Document Audit</p>
              <input type="file" onChange={handleUpload} className="text-xs w-full file:bg-zinc-800 file:text-white file:border-0 file:rounded-lg file:px-4 file:py-2 cursor-pointer" />
            </div>

            {/* TEXT ANALYSIS */}
            <textarea 
              className="w-full h-64 bg-zinc-900/50 border border-zinc-800 p-6 rounded-2xl text-sm outline-none focus:border-blue-500"
              value={text} 
              onChange={(e) => setText(e.target.value)}
              placeholder="Captured data analysis..."
            />
            
            <button onClick={handleAction} className="w-full bg-blue-700 py-4 rounded-xl font-black shadow-lg hover:bg-blue-600 transition-all">
                EXECUTE ADVERSARIAL HARDENING
            </button>
          </div>

          {/* SCOREBOARD */}
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-zinc-900 border border-zinc-800 p-8 rounded-2xl text-center relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-yellow-500"></div>
                <p className="text-[10px] text-yellow-500 font-bold uppercase mb-2 tracking-widest">Hacker Risk Score</p>
                <p className="text-7xl font-black text-yellow-500">{hardenedRisk}%</p>
              </div>
              <div className="bg-zinc-900 border border-zinc-800 p-8 rounded-2xl text-center relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-blue-500"></div>
                <p className="text-[10px] text-blue-500 font-bold uppercase mb-2 tracking-widest">Marketability</p>
                <p className="text-7xl font-black text-blue-500">+{result?.market_score || 0}%</p>
              </div>
            </div>

            {/* ADVERSARY LOGS */}
            {result && (
              <div className="bg-red-900/10 border border-red-500/30 p-6 rounded-2xl animate-in fade-in slide-in-from-bottom duration-700">
                <h3 className="text-[10px] font-bold text-red-500 uppercase mb-4 italic tracking-widest underline decoration-red-500/50">Reconnaissance Findings</h3>
                <div className="space-y-2">
                  {result.evidence?.map((e: string, i: number) => (
                    <div key={i} className="text-[10px] font-mono text-red-400 p-3 bg-black rounded-lg border border-red-900/50">
                      <span className="text-red-700 mr-2">▶</span> {e}
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* OVERLAY LOADING */}
      {loading && (
        <div className="fixed bottom-10 right-10 bg-red-600 px-8 py-4 rounded-full animate-pulse text-xs font-black border-2 border-white/20 z-50">
          SIMULATING ADVERSARY...
        </div>
      )}
    </div>
  );
}